import { connectDB } from "@/lib/db"
import Variable from "@/models/Variable"
import DealData from "@/models/DealData"
import { buildFinalData } from "@/lib/buildFinalData"
import { NextResponse } from "next/server"

export async function GET(req: any, { params }: any) {
  await connectDB()

  const propertyId = req.nextUrl.searchParams.get("propertyId")

  const variables = await Variable.find({ templateId: params.id })
  const dealData = await DealData.findOne({ propertyId })

  const final = buildFinalData(variables, {
    deal: dealData?.data || {},
  })

  return NextResponse.json(final)
}